DROP TABLE IF EXISTS `note_node`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `note_node` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `version` bigint NOT NULL DEFAULT '1' COMMENT '版本',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `created_by` bigint DEFAULT '-1' COMMENT '创建人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '最后修改时间',
  `updated_by` bigint DEFAULT '-1' COMMENT '最后修改人',
  `note_type` varchar(32) DEFAULT NULL,
  `parent_id` bigint DEFAULT NULL,
  `sort` int NOT NULL,
  `title` varchar(200) NOT NULL,
  `deleted` bit(1) NOT NULL COMMENT 'Soft-delete indicator',
  `path_ids` json DEFAULT NULL,
  `note_key` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_note_node_note_key` (`note_key`),
  KEY `idx_note_node_parent_id` (`parent_id`),
  KEY `idx_note_node_note_type` (`note_type`),
  KEY `idx_note_node_parent_sort` (`parent_id`,`sort`),
  KEY `idx_note_node_note_key` (`note_key`)
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
