INSERT INTO `question` VALUES (1,10,'2026-04-10 12:25:06',1,'2026-04-14 07:11:08',0,2,'ja-JP','{\"ext\": {\"source\": \"mock\"}, \"assets\": [], \"blanks\": [], \"display\": {\"score\": 1, \"section\": \"文字・語彙\", \"typeLabel\": \"选择题\"}, \"options\": [{\"key\": \"1\", \"sort\": 1, \"content\": {\"text\": \"寝ていました\", \"type\": \"text\"}}, {\"key\": \"2\", \"sort\": 2, \"content\": {\"text\": \"寝ました\", \"type\": \"text\"}}, {\"key\": \"3\", \"sort\": 3, \"content\": {\"text\": \"寝られます\", \"type\": \"text\"}}, {\"key\": \"4\", \"sort\": 4, \"content\": {\"text\": \"寝させました\", \"type\": \"text\"}}], \"analysis\": {\"text\": \"句子表示过去发生的动作，且“回家后马上睡了”，用过去式「寝ました」最自然。\", \"type\": \"text\"}, \"answerKey\": {\"optionKeys\": [\"2\"]}}','n3_mock_001','SINGLE_CHOICE','昨日は疲れていたので、家に帰ってすぐ（　）。','次の文の（　）に入る言葉として、最もよいものを一つ選びなさい。'),(2,3,'2026-04-10 12:25:06',1,'2026-04-10 12:39:29',0,2,'ja-JP','{\"ext\": {\"source\": \"mock\"}, \"assets\": [{\"url\": \"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3\", \"meta\": {\"format\": \"mp3\"}, \"type\": \"audio\"}], \"blanks\": [], \"display\": {\"score\": 1, \"section\": \"聴解\", \"typeLabel\": \"听力选择题\"}, \"options\": [{\"key\": \"1\", \"sort\": 1, \"content\": {\"text\": \"男の人は図書館へ行きます\", \"type\": \"text\"}}, {\"key\": \"2\", \"sort\": 2, \"content\": {\"text\": \"女の人は駅で待ちます\", \"type\": \"text\"}}, {\"key\": \"3\", \"sort\": 3, \"content\": {\"text\": \"二人は午後三時に会います\", \"type\": \"text\"}}, {\"key\": \"4\", \"sort\": 4, \"content\": {\"text\": \"男の人は今日は行きません\", \"type\": \"text\"}}], \"analysis\": {\"text\": \"这是听力题示例：先用占位音频。你可以替换成自己的日语 mp3。\", \"type\": \"text\"}, \"answerKey\": {\"optionKeys\": [\"3\"]}}','n3_mock_002','SINGLE_CHOICE','先听音频，再选择正确答案。','問題を聞いて、正しい答えを一つ選んでください。'),(3,4,'2026-04-10 12:25:07',1,'2026-04-10 12:27:39',0,2,'ja-JP','{\"ext\": {\"source\": \"mock\"}, \"assets\": [], \"blanks\": [{\"key\": \"blank_1\", \"hint\": \"ひらがな、または漢字\"}], \"display\": {\"score\": 1, \"section\": \"語彙\", \"typeLabel\": \"单词填写题\"}, \"options\": [], \"analysis\": {\"text\": \"句意是“这个包虽然有点重，但还没问题”，所以填「だいじょうぶ / 大丈夫」。\", \"type\": \"text\"}, \"answerKey\": {\"blanks\": {\"blank_1\": [\"だいじょうぶ\", \"大丈夫\"]}}}','n3_mock_003','FILL_BLANK','このかばんは少し重いですが、まだ（　）です。','文脈に合う言葉をひらがな、または漢字で書きなさい。');
