--
-- Table structure for table `word_card`
--

DROP TABLE IF EXISTS `word_card`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `word_card` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `version` bigint NOT NULL DEFAULT '1' COMMENT '版本',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `created_by` bigint DEFAULT '-1' COMMENT '创建人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '最后修改时间',
  `updated_by` bigint DEFAULT '-1' COMMENT '最后修改人',
  `card_code` varchar(100) NOT NULL,
  `locale` varchar(20) NOT NULL,
  `meta_info` json DEFAULT NULL,
  `word_text` varchar(200) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_word_card_code` (`card_code`),
  KEY `idx_word_card_card_code` (`card_code`),
  KEY `idx_word_card_locale` (`locale`),
  KEY `idx_word_card_word_text` (`word_text`)
) ENGINE=InnoDB AUTO_INCREMENT=1018 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

